function daysBetween(date1, date2) {
  const diff = new Date(date1).getTime() - new Date(date2).getTime();
  return Math.floor(diff / (1000 * 60 * 60 * 24));
}

const today = new Date();
const todayStr = today.toISOString().split('T')[0];

const yesterday = new Date();
yesterday.setDate(today.getDate() - 1);
const yesterdayStr = yesterday.toISOString().split('T')[0];

const results = [];

for (const item of items) {
  const data = item.json;

  const hireDate = data.HireDate ? data.HireDate.split('T')[0] : null;
  const startDate = data.StartDate ? data.StartDate.split('T')[0] : null;

  const daysSinceStart = startDate ? daysBetween(today, startDate) : null;

  let trigger = null;
  let reason = '';

  // 1. New Hire (HireDate is today or yesterday)
  if (hireDate && (hireDate === todayStr || hireDate === yesterdayStr)) {
    trigger = 'NEW_HIRE';
  }
  // 2. First Shift (StartDate = yesterday)
  else if (startDate && startDate === yesterdayStr) {
    trigger = 'FIRST_SHIFT';
  }
  // 3. 30-day check-in
  else if (
    daysSinceStart !== null &&
    daysSinceStart >= 30 &&
    daysSinceStart < 60 &&
    !data.OData__x0033_0DayEmailSent
  ) {
    trigger = '30_DAY';
  }
  // 4. 60-day check-in
  else if (
    daysSinceStart !== null &&
    daysSinceStart >= 60 &&
    daysSinceStart < 90 &&
    !data.OData__x0036_0DayEmailSent
  ) {
    trigger = '60_DAY';
  }
  // 5. 90-day check-in
  else if (
    daysSinceStart !== null &&
    daysSinceStart >= 90 &&
    !data.OData__x0039_0DayEmailSent
  ) {
    trigger = '90_DAY';
  }
  // No trigger matched — figure out why
  else {
    trigger = 'NONE';

    if (!hireDate && !startDate) {
      reason = 'No HireDate or StartDate on record';
    } else if (!startDate) {
      reason = 'No StartDate — cannot evaluate shift/day milestones';
    } else if (daysSinceStart !== null && daysSinceStart < 30) {
      reason = `Only ${daysSinceStart} days since StartDate — too early for 30-day milestone`;
    } else if (
      daysSinceStart >= 30 && daysSinceStart < 60 &&
      data.OData__x0033_0DayEmailSent
    ) {
      reason = '30-day email already sent';
    } else if (
      daysSinceStart >= 60 && daysSinceStart < 90 &&
      data.OData__x0036_0DayEmailSent
    ) {
      reason = '60-day email already sent';
    } else if (
      daysSinceStart >= 90 &&
      data.OData__x0039_0DayEmailSent
    ) {
      reason = '90-day email already sent';
    } else {
      reason = 'Did not match any trigger condition';
    }
  }

  results.push({
    json: {
      ...data,
      trigger,
      reason
    }
  });
}

return results;

const rows = $input.first().json.noneRows || [];

if (rows.length === 0) {
  return [{ json: { skip: true } }];
}

const tableRows = rows.map(r =>
  `<tr><td style="padding:6px 12px;border:1px solid #ddd;">${r.Id || ''}</td><td style="padding:6px 12px;border:1px solid #ddd;">${r.Title || ''}</td><td style="padding:6px 12px;border:1px solid #ddd;">${r.Email || ''}</td><td style="padding:6px 12px;border:1px solid #ddd;">${r.HireDate ? r.HireDate.split('T')[0] : ''}</td><td style="padding:6px 12px;border:1px solid #ddd;">${r.StartDate ? r.StartDate.split('T')[0] : ''}</td><td style="padding:6px 12px;border:1px solid #ddd;">${r.reason || ''}</td></tr>`
).join('');

const html = `<html><body style="font-family:Arial,sans-serif;"><h2>Daily Onboarding Workflow Summary</h2><p>The following <b>${rows.length}</b> active employee(s) did not match any trigger condition in today's run:</p><table style="border-collapse:collapse;border:1px solid #ddd;"><thead><tr style="background:#f4f4f4;"><th style="padding:6px 12px;border:1px solid #ddd;text-align:left;">ID</th><th style="padding:6px 12px;border:1px solid #ddd;text-align:left;">Name</th><th style="padding:6px 12px;border:1px solid #ddd;text-align:left;">Email</th><th style="padding:6px 12px;border:1px solid #ddd;text-align:left;">Hire Date</th><th style="padding:6px 12px;border:1px solid #ddd;text-align:left;">Start Date</th><th style="padding:6px 12px;border:1px solid #ddd;text-align:left;">Reason</th></tr></thead><tbody>${tableRows}</tbody></table><p style="color:#888;font-size:12px;margin-top:24px;">Automated message from the RAH onboarding workflow.</p></body></html>`;

return [{ json: { summaryHtml: html, count: rows.length, skip: false } }];

function daysBetween(date1, date2) {
  const diff = new Date(date1).getTime() - new Date(date2).getTime();
  return Math.floor(diff / (1000 * 60 * 60 * 24));
}

function localDateStr(d) {
  const yyyy = d.getFullYear();
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  return `${yyyy}-${mm}-${dd}`;
}

const today = new Date();
const todayStr = localDateStr(today);

const yesterday = new Date();
yesterday.setDate(today.getDate() - 1);
const yesterdayStr = localDateStr(yesterday);

const results = [];

for (const item of items) {
  const data = item.json;

  const hireDate = data.HireDate ? data.HireDate.split('T')[0] : null;
  const startDate = data.StartDate ? data.StartDate.split('T')[0] : null;

  const daysSinceStart = startDate ? daysBetween(today, startDate) : null;
  const daysSinceHire = hireDate ? daysBetween(today, hireDate) : null;

  let trigger = null;
  let reason = '';

  // ─── ACTION TRIGGERS (send an email) ───────────────────────────

  // 1. 90-day check-in
  if (
    daysSinceStart !== null &&
    daysSinceStart >= 90 &&
    !data.OData__x0039_0DayEmailSent
  ) {
    trigger = '90_DAY';
  }
  // 2. 60-day check-in
  else if (
    daysSinceStart !== null &&
    daysSinceStart >= 60 &&
    daysSinceStart < 90 &&
    !data.OData__x0036_0DayEmailSent
  ) {
    trigger = '60_DAY';
  }
  // 3. 30-day check-in
  else if (
    daysSinceStart !== null &&
    daysSinceStart >= 30 &&
    daysSinceStart < 60 &&
    !data.OData__x0033_0DayEmailSent
  ) {
    trigger = '30_DAY';
  }
  // 4. First Shift
  else if (
    daysSinceStart !== null &&
    daysSinceStart >= 1 &&
    daysSinceStart < 30 &&
    !data.StartDateEmailSent
  ) {
    trigger = 'FIRST_SHIFT';
  }
  // 5. New Hire — only if they haven't progressed past this stage yet
  else if (
    hireDate &&
    daysSinceHire !== null &&
    daysSinceHire >= 0 &&
    !data.NewHireEmailSent &&
    (daysSinceStart === null || daysSinceStart < 1) &&
    !data.StartDateEmailSent &&
    !data.OData__x0033_0DayEmailSent &&
    !data.OData__x0036_0DayEmailSent &&
    !data.OData__x0039_0DayEmailSent
  ) {
    trigger = 'NEW_HIRE';
  }

  // ─── NEEDS_ATTENTION (data issue — human action required) ──────

  // No dates at all on record
  else if (!hireDate && !startDate) {
    trigger = 'NEEDS_ATTENTION';
    reason = 'No HireDate or StartDate on record';
  }
  // HireDate in the future
  else if (hireDate && daysSinceHire < 0) {
    trigger = 'NEEDS_ATTENTION';
    reason = `HireDate is in the future (${Math.abs(daysSinceHire)} days away)`;
  }
  // StartDate in the future
  else if (startDate && daysSinceStart < 0) {
    trigger = 'NEEDS_ATTENTION';
    reason = `StartDate is in the future (${Math.abs(daysSinceStart)} days away)`;
  }
  // Has HireDate, already past new-hire window, still no StartDate
  // (Workflow is blocked from progressing — needs StartDate to continue)
  else if (
    hireDate &&
    !startDate &&
    data.NewHireEmailSent &&
    daysSinceHire >= 1
  ) {
    trigger = 'NEEDS_ATTENTION';
    reason = `New hire email sent ${daysSinceHire} days ago but no StartDate set — please add StartDate to continue onboarding`;
  }
  // Has HireDate but missed new-hire window AND no StartDate
  // (couldn't fire NEW_HIRE because of guard conditions, but also no StartDate)
  else if (
    hireDate &&
    !startDate &&
    !data.NewHireEmailSent &&
    daysSinceHire >= 1
  ) {
    trigger = 'NEEDS_ATTENTION';
    reason = `HireDate is ${daysSinceHire} days ago, no StartDate yet, and new-hire email not sent — please review`;
  }

  // ─── NO_ACTION (everything is fine, nothing to do right now) ──

  else {
    trigger = 'NO_ACTION';

    if (daysSinceStart === 0) {
      reason = 'StartDate is today — first-shift email will fire tomorrow';
    } else if (daysSinceStart >= 1 && daysSinceStart < 30 && data.StartDateEmailSent) {
      reason = `${daysSinceStart} days into employment — first-shift email sent, awaiting 30-day milestone`;
    } else if (daysSinceStart >= 30 && daysSinceStart < 60 && data.OData__x0033_0DayEmailSent) {
      reason = `${daysSinceStart} days into employment — 30-day email sent, awaiting 60-day milestone`;
    } else if (daysSinceStart >= 60 && daysSinceStart < 90 && data.OData__x0036_0DayEmailSent) {
      reason = `${daysSinceStart} days into employment — 60-day email sent, awaiting 90-day milestone`;
    } else if (daysSinceStart >= 90 && data.OData__x0039_0DayEmailSent) {
      const earlierSkipped =
        !data.OData__x0033_0DayEmailSent ||
        !data.OData__x0036_0DayEmailSent ||
        !data.StartDateEmailSent;
      reason = earlierSkipped
        ? `${daysSinceStart} days into employment — 90-day email sent (one or more earlier milestone emails were skipped)`
        : `${daysSinceStart} days into employment — all check-in emails complete`;
    } else if (
      hireDate && !startDate && data.NewHireEmailSent && daysSinceHire === 0
    ) {
      reason = 'New hire email sent today — awaiting StartDate';
    } else {
      reason = 'No action needed at this time';
    }
  }

  results.push({
    json: {
      ...data,
      trigger,
      reason
    }
  });
}

return results;

const employeeData = items.find(i => i.json.flagToUpdate)?.json;

if (!employeeData) {
  throw new Error('Could not find employee data item (missing flagToUpdate field)');
}

return [
  {
    json: {
      Id: employeeData.Id,
      flagToUpdate: employeeData.flagToUpdate,
      reason: `${employeeData.trigger} email sent on ${new Date().toISOString().split('T')[0]}`
    }
  }
];
